<script>
function gotoCard(id){
  document.querySelectorAll('.gtab').forEach(function(b){b.classList.remove('active');});
  var el=document.getElementById(id);
  if(el){
    var snav=document.querySelector('.snav');
    var tabs=document.getElementById('grammar-tabs');
    var psub=document.getElementById('psub-bar');var offset=(snav?snav.getBoundingClientRect().height:0)+(psub?psub.getBoundingClientRect().height:0)+(tabs?tabs.getBoundingClientRect().height:0)+16;
    var top=el.getBoundingClientRect().top+window.scrollY-offset;
    window.scrollTo({top:top,behavior:'smooth'});
    document.querySelectorAll('.gtab').forEach(function(b){
      if(b.getAttribute('onclick')&&b.getAttribute('onclick').includes(id))b.classList.add('active');
    });
  }
}
